impl.spec_text:
tracked struct Foo(ghost u64, tracked u64);

proof fn some_call(tracked y: u64) { }

proof fn t() {
    let tracked foo = Foo(5, 6);
    let tracked Foo { 1: b, 0: a } = foo;

    // Variable 'a' has the mode of field '0' (that is, spec)
    // some_call requires 'proof'
    // So this should fail
    some_call(a);
}

